106	func (s *Store) Trend(metricID string) (TrendSummary, error) {
107		history, err := s.History(metricID)
108		if err != nil {
109			return TrendSummary{}, err
110		}
111		if len(history) == 0 {
112			return TrendSummary{}, fmt.Errorf("no history for metric %q", metricID)
113		}
114		unit, err := singleHistoryUnit(metricID, history)
115		if err != nil {
116			return TrendSummary{}, err
117		}
118		summary := TrendSummary{MetricID: metricID, Min: history[0].Value, Max: history[0].Value, Latest: history[len(history)-1].Value, Unit: unit, UpdatedAt: history[len(history)-1].ObservedAt}
119		var sum float64
120		for _, rec := range history {
121			if rec.Value < summary.Min {
122				summary.Min = rec.Value
123			}
124			if rec.Value > summary.Max {
125				summary.Max = rec.Value
126			}
127			sum += rec.Value
128			summary.UpdatedAt = rec.ObservedAt
129		}
130		summary.Count = len(history)
131		summary.Average = sum / float64(len(history))
132		return summary, nil
133	}
